#include <stdio.h>
#include <stdlib.h>

void setZeroes(int **mat, int n, int m) {
    int firstColZero = 0;
    // First pass: use first row and column as markers
    for (int i = 0; i < n; ++i) {
        if (mat[i][0] == 0) firstColZero = 1;
        for (int j = 1; j < m; ++j) {
            if (mat[i][j] == 0) {
                mat[i][0] = 0;
                mat[0][j] = 0;
            }
        }
    }
    // Second pass: set zeros using markers (bottom-up)
    for (int i = n - 1; i >= 0; --i) {
        for (int j = m - 1; j >= 1; --j) {
            if (mat[i][0] == 0 || mat[0][j] == 0) mat[i][j] = 0;
        }
        if (firstColZero) mat[i][0] = 0;
    }
}

int main() {
    int N, M; scanf("%d %d", &N, &M);
    int **mat = (int**)malloc(N * sizeof(int*));
    for (int i = 0; i < N; ++i) {
        mat[i] = (int*)malloc(M * sizeof(int));
        for (int j = 0; j < M; ++j) scanf("%d", &mat[i][j]);
    }
    setZeroes(mat, N, M);
    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < M; ++j) {
            printf("%d", mat[i][j]);
            if (j + 1 < M) printf(" ");
        }
        printf("\n");
    }
    for (int i = 0; i < N; ++i) free(mat[i]);
    free(mat);
    return 0;
}

