void setZeroes(vector<vector<int>>& mat) {
    int n = mat.size();
    int m = mat[0].size();
    bool firstColZero = false;
    for (int i = 0; i < n; ++i) {
        if (mat[i][0] == 0) firstColZero = true;
        for (int j = 1; j < m; ++j) {
            if (mat[i][j] == 0) {
                mat[i][0] = 0;
                mat[0][j] = 0;
            }
        }
    }
    for (int i = n - 1; i >= 0; --i) {
        for (int j = m - 1; j >= 1; --j) {
            if (mat[i][0] == 0 || mat[0][j] == 0) mat[i][j] = 0;
        }
        if (firstColZero) mat[i][0] = 0;
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int N, M; cin >> N >> M;
    vector<vector<int>> mat(N, vector<int>(M));
    for (int i = 0; i < N; ++i)
        for (int j = 0; j < M; ++j) cin >> mat[i][j];
    setZeroes(mat);
    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < M; ++j) {
            cout << mat[i][j];
            if (j + 1 < M) cout << ' ';
