import sys

def setZeroes(mat):
    n = len(mat)
    m = len(mat[0])
    first_col_zero = False
    for i in range(n):
        if mat[i][0] == 0:
            first_col_zero = True
        for j in range(1, m):
            if mat[i][j] == 0:
                mat[i][0] = 0
                mat[0][j] = 0
    for i in range(n - 1, -1, -1):
        for j in range(m - 1, 0, -1):
            if mat[i][0] == 0 or mat[0][j] == 0:
                mat[i][j] = 0
        if first_col_zero:
            mat[i][0] = 0


def main():
    data = sys.stdin.read().strip().splitlines()
    N, M = map(int, data[0].split())
    mat = []
    for i in range(N):
        mat.append(list(map(int, data[i + 1].split())))
    setZeroes(mat)
    for row in mat:
        print(' '.join(map(str, row)))

if __name__ == "__main__":
    main()

